const today = new Date();
const sevenDaysAgo = new Date();
sevenDaysAgo.setDate(today.getDate() - 7);

return items.filter(item => {
  const dateStr = item.json.date_history;

  if (!dateStr) return false;

  const [day, month, year] = dateStr.split('-').map(Number);
  const rowDate = new Date(year, month - 1, day);

  return rowDate >= sevenDaysAgo && rowDate <= today;
});

let totalOpportunities = items.length;
let wonDeals = 0;
let lostDeals = 0;
let totalRevenue = 0;

let agentPerformance = {};

for (const item of items) {
  const stage = item.json.deal_stage;
  const value = Number(item.json.close_value) || 0;
  const agent = item.json.sales_agent;

  if (stage === "Won") {
    wonDeals++;
    totalRevenue += value;

    if (!agentPerformance[agent]) {
      agentPerformance[agent] = 0;
    }

    agentPerformance[agent]++;
  }

  if (stage === "Lost") {
    lostDeals++;
  }
}

const topAgents = Object.entries(agentPerformance)
  .map(([agent, wins]) => ({
    agent,
    wins
  }))
  .sort((a, b) => b.wins - a.wins)
  .slice(0, 3);

return [
  {
    json: {
      totalOpportunities,
      wonDeals,
      lostDeals,
      totalRevenue,
      topAgents
    }
  }
];

